window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]=window.__LIBQ["the-gioi-hoan-my"]["q03"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]["artifacts"]={"updatedAt":"2026-07-05","count":100,"artifacts":[{"id":"ngan-dao-thu","name":"Ngân Đào thụ","aliases":["Ngân Đào"],"category":"linh-khi","categoryLabel":"Linh dược","phamCap":"Chuẩn Thánh dược","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Cây bạc chuẩn Thánh dược Nhóc Tỳ đào từ Bách Đoạn Sơn, đã kết hai quả, sắp tiến hóa thành Thánh dược chân chính.","detail":"Cây bạc to bằng cổ tay, cao nửa thân người, cành lá màu bạc như lửa bạc, đã kết hai quả ngả vàng nhạt. Nhóc Tỳ trồng giữa Thạch thôn, vùi bùn cát vàng kim để nuôi dưỡng; cây có cơ hội tiến hóa thành Thánh dược chân chính.","nguon":["@c0201"]},{"id":"bat-tran-ke","name":"Bát Trân Kê","category":"khac","categoryLabel":"Di chủng / Sinh linh quý","phamCap":"Di chủng Thái Cổ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Gà đất di chủng thành tinh biết độn thổ, trứng sánh linh dược; cả Thạch quốc chỉ hoàng thất có một con.","detail":"Con gà đất di chủng đã thành tinh, biết độn thổ nên khó phòng bị. Trứng nó đẻ ra sánh với linh dược, nửa tháng một quả. Sổng khỏi túi Càn Khôn làm loạn, nằm lười dưới gốc cây liễu và quỳ lạy thần thụ, coi thường Đại Hồng Điểu. Dòng tộc gà đất nổi danh khắp thiên hạ thời Thái Cổ, xuất thân chưa chắc kém Đại Hồng Điểu.","nguon":["@c0201"]},{"id":"kiem-do-rang-nanh-phi-di","name":"Kiếm đỏ răng nanh Phì Di","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Thanh kiếm màu máu luyện từ răng nanh của Phì Di, sắc nhọn với phù văn cường đại.","detail":"Bảo cụ chiến lợi phẩm của Nhóc Tỳ, luyện từ răng nanh màu máu của Phì Di, sắc nhọn và mang phù văn cường đại; nằm trong hơn mười kiện bảo cụ tặng thôn dân.","nguon":["@c0201"]},{"id":"sung-thu-chan-vo","name":"Sừng thú chấn vỡ","category":"phap-bao","categoryLabel":"Bảo cụ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Sừng thú thổi lên phát tiếng ù ù chấn vỡ thân thể, đoạt từ đệ tử Võ Vương phủ Thạch quốc.","detail":"Bảo cụ Nhóc Tỳ đoạt từ đệ tử Võ Vương phủ Thạch quốc; thổi lên phát ra tiếng ù ù có thể chấn vỡ thân thể đối phương.","nguon":["@c0201"]},{"id":"to-khi-thach-thon","name":"Tổ khí Thạch thôn","category":"phap-bao","categoryLabel":"Bảo cụ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Hai kiện pháp bảo cường đại do tổ tiên Thạch thôn truyền lại, chỉ dùng khi gặp đại họa.","detail":"Hai kiện tổ khí là pháp bảo cường đại do tổ tiên Thạch thôn truyền lại, chỉ được đem ra dùng khi thôn gặp đại họa.","nguon":["@c0201"]},{"id":"than-dich-thuan-huyet","name":"Thần dịch thuần huyết","aliases":["Bốn giọt thần dịch"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cực phẩm","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bốn giọt chất lỏng cô đặc luyện từ huyết nhục sinh linh thuần huyết, quý hơn hơn mười con thái cổ di chủng, chuẩn bị cho tẩy lễ của Nhóc Tỳ.","detail":"Do Liễu Thần luyện hóa từ bốn khối huyết nhục sinh linh thuần huyết: giọt màu mặc ngọc (huyết Thôn Thiên Tước), giọt đỏ như huyết (huyết Cùng Kỳ), giọt màu vàng và giọt trắng tinh (sinh linh Nam Vẫn Thần Sơn và Nghi Sơn). Bốn giọt được chứa trong bốn bình ngọc, đánh giá quý hơn cả hơn mười con thái cổ di chủng, dành cho việc tẩy lễ của Nhóc Tỳ mà Liễu Thần từng hứa.","nguon":["@c0202"]},{"id":"bot-xuong-thuan-huyet","name":"Bột xương sinh linh thuần huyết","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Nhị Ngốc Tử"],"trangThai":"dang-co","blurb":"Bột trắng như hoa tuyết do Tiểu Tháp nhả ra, có thể làm thành thuốc, được Nhị Ngốc Tử đánh giá là vô giá.","detail":"Khi Liễu Thần điều khiển Tiểu Tháp nhả huyết nhục, nó đồng thời nhả ra thứ bột trắng như hoa tuyết. Nhị Ngốc Tử nhận ra đây là dược liệu vô giá có thể luyện thành thuốc.","nguon":["@c0202"]},{"id":"binh-ngoc-chua-than-dich","name":"Bình ngọc chứa thần dịch","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bốn bình ngọc mài dũa từ linh ngọc tốt nhất, dùng để chứa bốn giọt thần dịch thuần huyết.","detail":"Vật chứa được mài dũa từ linh ngọc tốt nhất, dùng để bảo quản bốn giọt thần dịch mà Liễu Thần luyện hóa cho việc tẩy lễ của Nhóc Tỳ.","nguon":["@c0202"]},{"id":"huyet-nhuc-thon-thien-tuoc","name":"Huyết nhục Thôn Thiên Tước","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Tảng huyết nhục mấy ngàn cân lóe sáng đen bóng của Thôn Thiên Tước, luyện ra giọt thần dịch màu mặc ngọc.","detail":"Do Tiểu Tháp nhả ra, tảng huyết nhục mấy ngàn cân lóe sáng đen bóng, tỏa chấn động chí cường khiến người kinh sợ. Liễu Thần cắm cành liễu luyện hóa nó thành giọt thần dịch màu mặc ngọc.","nguon":["@c0202"]},{"id":"huyet-nhuc-cung-ky","name":"Huyết nhục Cùng Kỳ","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Tảng huyết nhục mấy ngàn cân bắn ra hào quang đỏ thẫm của Cùng Kỳ, luyện ra giọt thần dịch đỏ như huyết.","detail":"Do Tiểu Tháp nhả ra, tảng huyết nhục mấy ngàn cân bắn ra hào quang đỏ thẫm, mang chấn động chí cường kinh người. Liễu Thần luyện hóa nó thành giọt thần dịch đỏ như huyết.","nguon":["@c0202"]},{"id":"dia-hoang-hoa","name":"Địa Hoàng Hỏa","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Ngọn lửa mà Tiểu Tháp từng dẫn dụ ở Bách Đoạn Sơn để rèn luyện và chữa trị thân tháp.","detail":"Được nhắc lại trong lời giải thích về Tiểu Tháp: tại Bách Đoạn Sơn, Tiểu Tháp từng dẫn Địa Hoàng Hỏa rèn luyện thân mình, cho thấy nó đang tự chữa trị và hoàn thiện thân tháp.","nguon":["@c0202"]},{"id":"bao-huyet-thai-co-di-chung","name":"Bảo huyết của thái cổ di chủng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thái cổ","soHuu":[],"trangThai":"dang-co","blurb":"Bảo vật huyết mạch của giống loài thái cổ còn sót lại, quý giá ngang nguyên thủy bảo cốt. Được hai lão con hàng nêu làm điều kiện giao dịch tin tức về Hùng Hài Tử.","detail":"Bảo huyết của thái cổ di chủng là loại bảo vật trân quý mà Điểu Gia và Tinh Bích đại gia đòi làm giá đổi tin tức, đặt ngang hàng với nguyên thủy bảo cốt; hai lão yêu cầu trưởng tộc các tộc phải đích thân mang tới giao dịch.","nguon":["@c0203","@c0204"]},{"id":"nguyen-thuy-phu-cot","name":"Nguyên thủy phù cốt","category":"nguyen-lieu","categoryLabel":"Vật phẩm quý","phamCap":"Quý hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Thứ quý hiếm được hai lão già chấp nhận thay bảo huyết để đổi tin tức tung tích Nhóc Tỳ.","detail":"Nguyên thủy phù cốt là vật phẩm quý hiếm mà Tinh Bích đại gia và Điểu Gia chấp nhận thay cho bảo huyết thái cổ di chủng khi ra giá trao đổi tin tức tung tích Nhóc Tỳ tại Sơ Thủy Địa.","nguon":["@c0204"]},{"id":"ly-hoa-than-tam","name":"Ly Hỏa Thần Tàm","cn":"","category":"nguyen-lieu","categoryLabel":"Thái cổ di chủng","phamCap":"Thái cổ di chủng / hung vật","soHuu":["Tứ công tử Thác Bạt Tộc","Nhóc Tỳ"],"trangThai":"Đã bị bóp chết, huyết nhục cất làm bảo dược","blurb":"Con tằm thái cổ di chủng đỏ như ngọc, phun tơ mang Ly Hỏa đốt người thành tro.","detail":"Ly Hỏa Thần Tàm là một con tằm thái cổ di chủng lớn cỡ một thước, toàn thân đỏ sậm gần như trong suốt tựa ngọc, bên ngoài lượn lờ hỏa diễm. Tơ nó nhả ra cứng cỏi khó cắt và mang theo Ly Hỏa có thể thiêu người thành tro. Tứ công tử Thác Bạt Tộc ôm nó, dùng nó phun tơ đan lưới để bắt sống Nhóc Tỳ. Trong trận đối đầu ở Sơ Thủy Địa, Nhóc Tỳ dùng Kim Tuyền Ba Văn Công nuốt sạch Ly Hỏa rồi đoạt lấy con tằm. Thấy không thể thuần phục di chủng này, nó dùng sức bóp chết con tằm rồi cất huyết nhục vào túi làm bảo dược.","nguon":["@c0205"]},{"id":"ly-hoa-tam-ti","name":"Ly Hỏa Tàm Ti","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ (tơ tằm tế luyện)","soHuu":["Tứ công tử Thác Bạt Tộc"],"trangThai":"Đã bị Nhóc Tỳ xé rách","blurb":"Lưới thiên la địa võng dệt từ tơ Ly Hỏa Thần Tàm, được lão tổ Thác Bạt Tộc gia trì phù văn.","detail":"Ly Hỏa Tàm Ti là loại tơ do Ly Hỏa Thần Tàm phun ra, đã trải qua tế luyện của lão tổ Thác Bạt Tộc và được gia trì nhiều phù văn thần bí. Sợi tơ được đan thành một tấm lưới thiên la địa võng cực bền, mang theo Ly Hỏa, dùng để trói buộc và bắt sống đối thủ. Tứ công tử Thác Bạt Tộc giăng lưới này định bắt Nhóc Tỳ, nhưng sau khi Ly Hỏa bị Kim Tuyền Ba Văn Công nuốt sạch, Nhóc Tỳ dùng hai tay xé rách tấm lưới, tơ đứt gãy răng rắc, phô bày thần lực đáng sợ.","nguon":["@c0205"]},{"id":"binh-ngoc-bao-huyet","name":"Bình ngọc bảo huyết","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Vật phẩm chứa bảo huyết","soHuu":["Nhóc Tỳ"],"trangThai":"Bị Nhóc Tỳ cướp, bọc trong tấm da thú","blurb":"Đống bình ngọc đựng bảo huyết của thái cổ di chủng mà Nhóc Tỳ cướp được.","detail":"Bình ngọc bảo huyết là những chiếc bình ngọc chứa bảo huyết chiết xuất từ thái cổ di chủng. Trong trận ở Sơ Thủy Địa, Nhóc Tỳ nhanh tay bọc cả một đống bình ngọc bảo huyết vào tấm da thú khoác sau lưng rồi phá vòng vây thoát ra. Chính đống bảo huyết này là nguyên nhân khiến Tinh Bích, Điểu Gia cùng Vũ Tộc và tứ đại gia tộc mắt đỏ lên xông tới truy sát nó.","nguon":["@c0205"]},{"id":"diet-hon-cham","name":"Diệt Hồn Châm","cn":"","category":"khac","categoryLabel":"Ma khí","phamCap":"Ma khí bao hàm sức mạnh trật tự","soHuu":["Nhóc Tỳ","Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Thần châm đỏ đậm tế luyện tại Hư Thần Giới, giết được cả hư thân lẫn chân thân ở hiện thực; gồm mười hai cây, mỗi cây giết một người thì tiêu tán.","detail":"Ma khí đỏ đậm do Thác Bạt Tộc tung ra, tế luyện tại Hư Thần Giới từ vật liệu đặc biệt bao hàm một phần sức mạnh trật tự. Có thể diệt cả thần thức ở hiện thực khiến chân thân chết. Gồm mười hai cây, mỗi cây giết được một người rồi tiêu tán. Nhóc Tỳ né tránh rồi dùng đỉnh lôi điện tím hút lấy và dùng phù văn mi tâm khống chế, đoạt mất khiến Thác Bạt Tộc và chư giáo không đoạt lại được; Nhóc Tỳ giữ lại để về sau đối phó cao tầng các giáo.","nguon":["@c0206","@c0213"]},{"id":"than-tam-ly-hoa","name":"Thần tằm Ly Hỏa","cn":"","category":"khac","categoryLabel":"Di chủng","phamCap":"Di chủng thượng cổ","soHuu":["Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Di chủng tìm được từ động thiên phúc địa, bị lão tổ Thác Bạt Tộc thuần phục và luyện ra phù văn từ cơ thể nó.","detail":"Thần tằm Ly Hỏa được Tứ công tử Thác Bạt tộc tìm thấy từ động thiên phúc địa trong Hư Thần Giới. Về sau bị lão tổ trong tộc thuần phục và luyện ra phù văn từ cơ thể nó.","nguon":["@c0206"]},{"id":"vat-than-bi-ky-luc-giet-choc","name":"Vật thần bí phần thưởng kỷ lục","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Một vật được luồng hào quang mông lung từ trời bao quanh, rơi tới gần Nhóc Tỳ sau khi nó lập kỷ lục giết chóc; bản chất chưa rõ.","detail":"Sau khi Nhóc Tỳ lập kỷ lục giết chóc tại Sơ Thủy Địa, một luồng hào quang mông lung từ trên trời giáng xuống bao quanh một thứ và dần dần rơi tới gần nó. Bản chất và công dụng của vật này chưa được tiết lộ.","nguon":["@c0206"]},{"id":"sach-than-thai-co","name":"Sách Thần Thái Cổ","aliases":["Thái Cổ Thần Thư","Sách quý đồng thau","Sách thần đồng thau","mảnh vỡ đồng thau"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thánh vật Thái Cổ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Mảnh kim loại đồng thau dị thường cực cứng, là một phần mười của một cuốn sách thần thời Thái Cổ, do pháp tắc trật tự thế giới ban xuống khi Nhóc Tỳ lập kỷ lục.","detail":"Một chùm sáng như đèn lồng giáng xuống rồi nứt ra để lộ mảnh đồng thau cứng đến mức cắn cũng không nát, được xác nhận chiếm một phần mười của sách thần thời Thái Cổ. Nếu gom đủ toàn bộ các mảnh vỡ đồng thau sẽ mở ra một tòa tiên tàng chứa những bảo thuật cái thế của thời đại Thái Cổ, được ví như nguyên thủy phù cốt vô thượng chứa đựng đại thần thông — vật mà cả hung thú thuần huyết lẫn chim thần đều hằng mơ ước. Muốn thu các mảnh còn lại phải tiếp tục phá những kỷ lục gian nan nhất, gần như không thể hoàn thành.","nguon":["@c0207"]},{"id":"thanh-vat-than-bi-nghi-nhi","name":"Thánh vật thần bí của Nghị nhi","category":"khac","categoryLabel":"Khác","phamCap":"Thánh vật (chưa rõ)","soHuu":["Nghị nhi"],"trangThai":"dang-co","blurb":"Báu vật mà Nghị nhi của Vũ Tộc từng nhận được và giấu kín, nghe nói giá trị không kém Sách Thần Thái Cổ.","detail":"Được nhắc tới gián tiếp trong lúc Vũ Tộc bàn tính đối phó Nhóc Tỳ; một thánh vật thần bí giấu kín, chưa lộ hình dạng hay công năng, nghe nói không thua kém Sách Thần Thái Cổ.","nguon":["@c0207"]},{"id":"sach-quy-dong-thau","name":"Sách quý đồng thau","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bí điển thần cấp","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ giữ, chỉ cho hai lão xem một góc vỡ chưa giao hẳn","blurb":"Sách thần bằng đồng thau, chỉ một mảnh nhỏ xuất hiện đã kinh động các lão tổ gia tộc Thượng Cổ.","detail":"Còn gọi là sách thần bằng đồng thau. Khi một mảnh nhỏ của nó lộ ra đã kinh động đến các lão tổ gia tộc Thượng Cổ, khiến bọn họ bàn tán xôn xao. Nhóc Tỳ nắm giữ và dùng nó làm quân bài mặc cả: chỉ cho Tinh Bích đại gia cùng Điểu gia xem một góc vỡ bằng đồng thau nhưng chưa giao hẳn, hé mở khả năng hợp tác về sau quanh bí điển này.","nguon":["@c0208"]},{"id":"bao-huyet-di-chung","name":"Bảo huyết di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chưa rõ","soHuu":["Vũ Tộc","Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Bảo huyết của sinh linh di chủng mà Hùng Hài Tử đòi các gia tộc nộp mười bình mỗi tộc.","detail":"Thứ Hùng Hài Tử ra lệnh mỗi gia tộc, bắt đầu từ Vũ Tộc và Thác Bạt Tộc, phải nộp mười bình trong hạn một canh giờ; nếu không giao nó sẽ tự tới lấy. Đây là một phần hành động báo thù các thế lực từng huyết chiến với Bổ Thiên Các.","nguon":["@c0209"]},{"id":"bao-phien-mau-uyen-toc","name":"Bảo phiến màu máu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trấn tộc","phamCap":"Bảo vật trấn tộc Uyên Tộc","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Quạt màu đỏ, bảo vật trấn tộc Uyên Tộc, Nhóc Tỳ đoạt từ tứ đại gia tộc ở Sơ Thủy Địa; vỗ ra hỏa diễm ngập trời.","detail":"Bảo phiến màu máu là chí bảo trấn tộc của Uyên Tộc bị Nhóc Tỳ cướp từ tứ đại gia tộc ở Sơ Thủy Địa. Khi vỗ ra, quạt phun hỏa diễm ngập trời như núi lửa phun trào, thiêu Ngân Thiên Lang thành Hỏa Lang trong trận chiến với Vũ Tộc ở Hư Thần Giới.","nguon":["@c0210"]},{"id":"ngan-thien-lang","name":"Ngân Thiên Lang","cn":"","aliases":["Khuyết Nguyệt Thiên Lang"],"category":"phap-bao","categoryLabel":"Bảo cụ hóa hung thú","phamCap":"Dị chủng Thái Cổ (tấm da)","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tấm da thú dị chủng Thái Cổ của Vũ Tộc, tế ra hóa thành hung thú cao như núi; bị Nhóc Tỳ đánh gãy xương sống, thiêu cháy còn lại tấm da sói thủng lỗ.","detail":"Vũ Tộc tế ra tấm da thú dị chủng Thái Cổ hóa thành Khuyết Nguyệt Thiên Lang (Ngân Thiên Lang), hung thú cao như núi với đầu sói, sừng, đuôi cá sấu, có cánh và vảy bạc. Nhóc Tỳ dùng bảo phiến máu thiêu nó thành Hỏa Lang rồi dùng quyền tím đánh gãy xương sống, buộc Vũ Tộc thu hồi khi chỉ còn tấm da sói cháy đen thủng lỗ tối đen.","nguon":["@c0210"]},{"id":"phao-dai-bao-cot-vu-toc","name":"Pháo đài bảo cốt Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Chí bảo trấn tộc","phamCap":"Báu vật vô giá","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tòa kiến trúc cổ xưa chứa nhiều bảo cốt, chí bảo trấn tộc của Vũ Tộc; bị kiếm gãy Nhóc Tỳ đánh nổ tung.","detail":"Một tòa pháo đài (kiến trúc cổ) từ dưới đất nhô lên, ẩn chứa nhiều bảo cốt và tỏa ánh sáng giết chóc, là báu vật vô giá được Vũ Tộc tế luyện nhiều năm. Trong trận chiến, Nhóc Tỳ dùng kiếm gãy đánh nổ tung tòa pháo đài, khiến các lão Vũ Tộc phun máu.","nguon":["@c0210"]},{"id":"phap-chi-than-linh","name":"Pháp chỉ của Thần Linh","aliases":["Pháp chỉ chữ Phạt"],"category":"than-khi","categoryLabel":"Di vật thần","phamCap":"Di vật Thần Linh","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Tấm pháp chỉ cuối cùng Vũ Thần lưu lại, gồm mười tờ giấy màu vàng đất nát bét ghép lại; ghép đủ mới đại biểu ý chí Thần Linh.","detail":"Pháp chỉ được đựng trong bình đen đặt trên tế đàn trong miếu thần Vũ Tộc, khi mở ra khí tức bùng lên như Thần Linh xuất thế. Mười tờ giấy vàng đất mỗi tờ mang ít chữ viết, ghép đủ mới đại biểu ý chí Thần Linh. Tờ Vũ Tử Mạch chọn ghi chữ “Phạt”, tuy không phải “Giết” nhưng đủ mạnh chém bất kỳ địch thủ nào trong Hư Thần Giới. Pháp chỉ khắc bằng ý chí tinh thần, hơn xa các chí bảo khác và hơn xa tờ giấy không chữ ở Bách Đoạn Sơn (thứ kia chỉ là hư). Khi bộc phát, nó ảnh hưởng cả quy tắc trật tự Hư Thần Giới, trút mưa ánh sáng vàng đánh Nhóc Tỳ đầy lỗ máu.","nguon":["@c0211"]},{"id":"binh-den-phap-chi","name":"Bình đen","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Chiếc bình toàn thân đen thui, lấm tấm như giọt mưa, dùng đựng mười tờ pháp chỉ nát của Vũ Thần.","detail":"Bình đen được đặt trên tế đàn nhỏ trước tượng thần trong miếu thần Vũ Tộc. Khi mở ra vọt lên khí tức kinh khủng như Thần Linh xuất thế, bên trong là mười tờ giấy màu vàng đất ghép thành pháp chỉ. Sau khi lấy tờ chữ “Phạt”, các tờ còn lại được đưa lại vào bình, đậy nắp và đặt về tế đàn.","nguon":["@c0211"]},{"id":"binh-bao-huyet-tri-thuong","name":"Bình bảo huyết","category":"dan-duoc","categoryLabel":"Đan dược / Vật phẩm","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"da-dung","blurb":"Bình bảo huyết Nhóc Tỳ dùng để trị thương giữa trận quyết đấu.","detail":"Trong lúc quyết đấu với pháp chỉ Vũ Thần và trọng thương, Nhóc Tỳ lấy ra bình bảo huyết, mở nắp uống ừng ực để trị thương rồi tiếp tục chiến đấu.","nguon":["@c0212"]},{"id":"phap-chi-vu-than-phat","name":"Pháp chỉ Vũ Thần (chữ Phạt)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp chỉ Thần Linh","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tờ giấy vàng đất mang ý chí Thần Linh chữ “Phạt”, phóng thần uy nhưng cuối cùng vỡ nát và bị Nhóc Tỳ ăn.","detail":"Tờ giấy vàng đất mang ý chí Thần Linh của Vũ Thần, khắc chữ “Phạt”, phóng ra thần uy nhằm tiêu diệt kẻ địch. Bị tiểu tháp va chạm cùng kiếm gãy chém nên không ổn định, cuối cùng vỡ nát chỉ còn lại một tờ giấy bị cắt làm hai nửa và mất ý chí Thần Linh. Nhóc Tỳ nhét cả hai nửa vào miệng nhai nuốt, khiến các lão giả Vũ Tộc hộc máu vì cho là xúc phạm Thần Linh.","nguon":["@c0213"]},{"id":"tran-hon-thap","name":"Trấn Hồn Tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Công cụ Vũ Tộc dùng để giết hồn phách và luyện hóa, định biến chân thân Nhóc Tỳ thành thân tử đạo tiêu.","detail":"Pháp bảo của Vũ Tộc chuyên giết hồn phách và luyện hóa. Sau khi cấm trận kích nổ khiến Nhóc Tỳ trọng thương, bọn Vũ Tộc định dùng Trấn Hồn Tháp để biến chân thân của nó thành “thân tử đạo tiêu”.","nguon":["@c0213"]},{"id":"than-chu-vu-toc","name":"Thần chu Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Thần chu Vũ Tộc là chiếc thuyền thần màu xanh da trời, phủ phù văn và có tốc độ cực nhanh. Nó được điều đến chặn đường Nhóc Tỳ khi cậu định rời tịnh thổ để mở Động Thiên thứ mười.","detail":"Chiếc thần chu chở nhiều cao thủ Vũ Tộc vượt lên chặn trước Nhóc Tỳ. Trong cuộc phản công, Nhóc Tỳ triệu Côn Bằng ngậm kiếm gãy chém đứt một khúc thân thuyền, buộc các cao thủ trên thuyền phải bỏ chạy.","nguon":["@c0214"]},{"id":"bao-an-vu-toc","name":"Bảo ấn Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trấn áp","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Bảo ấn Vũ Tộc là pháp bảo được tế luyện nhiều năm, có thể hóa thành ngọn núi để trấn áp đối thủ. Trong chương 214, nó bị bảo thuật Côn Bằng của Nhóc Tỳ đâm nát thành tro.","detail":"Bảo ấn khi được thả ra hóa thành một ngọn núi có cây cối chim cá, mang uy thế đè ép mạnh mẽ. Nhóc Tỳ dùng Côn Bằng khổng lồ lao thẳng lên trời, phá hủy bảo ấn ngay trong đợt phản kích của Vũ Tộc.","nguon":["@c0214"]},{"id":"phu-tien-vu-toc","name":"Phù tiễn Vũ Tộc","cn":"","aliases":["Mũi tên cốt văn"],"category":"khac","categoryLabel":"Vũ khí cốt văn","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"da-dung","blurb":"Phù tiễn Vũ Tộc là hàng vạn mũi tên khắc cốt văn được bắn ra để ngăn Nhóc Tỳ đột phá. Chúng có lực sát thương lớn nhưng bị Toan Nghê tím do lôi điện hóa thành phá tan.","detail":"Trong trận tịnh thổ, Vũ Tộc bắn hàng vạn phù tiễn khắc cốt văn, đủ sức phá thành trì núi non. Nhóc Tỳ triệu Toan Nghê màu tím dựng thế lôi điện, chặn phá toàn bộ làn mưa tên này.","nguon":["@c0214"]},{"id":"mieng-thanh-dong","name":"Miếng thanh đồng","cn":"","aliases":["Miếng đồng thau"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ đang giữ","blurb":"Miếng thanh đồng là vật quý trên người Nhóc Tỳ bị Thác Bạt Tộc nhắm tới. Nhị công tử Thác Bạt Tộc nhường phần đoạt vật này cho Lục công tử nộp lên tộc.","detail":"Trong cuộc truy sát ở khu rừng Hư Thần Giới, các công tử Thác Bạt nhắc tới miếng thanh đồng trên người Nhóc Tỳ như một chiến lợi phẩm quan trọng. Giá trị và công dụng cụ thể chưa được nói rõ, nhưng đủ khiến người của Thác Bạt Tộc muốn đoạt lấy để dâng lên trong tộc.","nguon":["@c0217"]},{"id":"ma-cham-mau-do-dam","name":"Ma châm màu đỏ đậm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Ma khí","phamCap":"Chưa rõ","soHuu":["Lục công tử Thác Bạt Tộc"],"trangThai":"Đang sử dụng","blurb":"Ma châm màu đỏ đậm là vũ khí Lục công tử Thác Bạt Tộc lấy ra khi truy sát Nhóc Tỳ. Nó phát ánh sáng lạnh buốt và được dùng với ý đồ tiêu diệt cả hư thân lẫn chân thân.","detail":"Khi cùng Nhị công tử Thác Bạt Tộc cá cược giết Nhóc Tỳ, Lục công tử lấy ra ma châm màu đỏ đậm. Vật này được mô tả là âm độc, nhằm khiến Nhóc Tỳ chết trong Hư Thần Giới và liên lụy tới chân thân.","nguon":["@c0217"]},{"id":"cham-than-mau-do-luc-cong-tu","name":"Châm thần màu đỏ","cn":"","aliases":["Châm thần màu đỏ của Lục công tử"],"category":"phap-bao","categoryLabel":"Châm thần","phamCap":"Không rõ","soHuu":["Lục công tử Thác Bạt Tộc","Nhóc Tỳ"],"trangThai":"bị đoạt","blurb":"Châm thần đỏ đậm trong tay Lục công tử Thác Bạt Tộc. Khi Nhóc Tỳ kéo hắn tới, vật này bị đoạt rồi dùng để đâm vào đầu hắn, khiến thần hồn hủy diệt.","detail":"Chương không nói thẳng châm thần này đồng nhất với Diệt Hồn Châm của Nhị công tử, nên ghi riêng theo mô tả xuất hiện. Nó thể hiện cùng kiểu pháp bảo công kích thần hồn, đủ khiến chân thân liên đới chết theo khi thần hồn bị hủy.","nguon":["@c0218"]},{"id":"ma-khi","name":"Ma khí","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tứ đại gia tộc Côn, Ly, Mông, Uyên","Nhóc Tỳ"],"trangThai":"bị Nhóc Tỳ cướp sạch khỏi đám đầu lĩnh","blurb":"Vật phẩm đặc biệt do tứ đại gia tộc Côn, Ly, Mông, Uyên mang ra để đối phó Nhóc Tỳ.","detail":"Tứ đại gia tộc nắm giữ ma khí và lấy ra vật quan trọng nhất trong tộc, muốn trả giá lớn để giết cả hư thân lẫn chân thân của Nhóc Tỳ. Khi giao chiến, các đầu lĩnh bị Nhóc Tỳ đánh bại và ma khí bị cướp sạch.","nguon":["@c0219"]},{"id":"to-khi-thac-bat-toc","name":"Tổ Khí Thác Bạt Tộc","cn":"","aliases":["Tổ Khí"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"bảo cụ đặc biệt","soHuu":["Lão tổ Thác Bạt Tộc","Thác Bạt Tộc"],"trangThai":"đang được Thác Bạt Tộc nắm giữ","blurb":"Bảo cụ đặc biệt của Thác Bạt Tộc, có năng lực súc địa thành thốn và có thể mang vào Hư Thần Giới. Lão tổ Thác Bạt Tộc dùng nó để bọc người còn lại chạy thoát khỏi Nhóc Tỳ.","detail":"Sau khi tịnh thổ Thác Bạt Tộc bị đánh tan, lão tổ lấy Tổ Khí quấn quanh nhóm người sống sót, hóa thành một vùng sáng lao tới cuối đại địa và biến mất. Công dụng nổi bật được nêu ở chương này là di chuyển cực nhanh theo kiểu súc địa thành thốn.","nguon":["@c0220"]},{"id":"bao-tay-cua-lao-gia","name":"Bao tay của lão già","cn":"","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Binh khí của Thần minh","soHuu":["Lão già tổ phụ của thiếu nữ áo tím"],"trangThai":"đang sử dụng","blurb":"Bao tay của lão già là chí bảo có khí tức thần linh, được chính lão gọi là binh khí của Thần minh. Nó giúp lão chống cự Nhóc Tỳ, đồng thời khiến Nhóc Tỳ nảy ý đoạt lấy.","detail":"Trong trận ở Hư Thần Giới, Nhóc Tỳ nhận ra bao tay của lão già có khí tức thần linh và lập tức đòi lấy. Lão dùng nó để chống đỡ sức công phạt của Nhóc Tỳ, sau đó tiết lộ đây là binh khí của Thần minh nhằm dọa đối phương, nhưng Nhóc Tỳ vẫn không buông ý định đoạt bảo.","nguon":["@c0221"]},{"id":"bong-tai-cua-thieu-nu","name":"Bông tai của thiếu nữ","cn":"","category":"phap-bao","categoryLabel":"Chí bảo phòng ngự","phamCap":"Có sức mạnh của Thần","soHuu":["Thiếu nữ áo tím"],"trangThai":"đang sử dụng","blurb":"Bông tai của thiếu nữ áo tím là chí bảo phòng ngự được chí cường giả tế luyện. Khi vận dụng, nó tạo màn sáng có sức mạnh của Thần chuyển động để ngăn Nhóc Tỳ áp sát.","detail":"Thiếu nữ áo tím lấy bông tai ra trong lúc đối đầu Nhóc Tỳ, dùng sức mạnh được chí cường giả tế luyện để ngăn thế công cận chiến. Nhóc Tỳ vẫn đánh xuyên qua lớp phòng ngự, nhưng cũng nhận xét vật này tốt hơn bảo vật trước đó của nàng.","nguon":["@c0221"]},{"id":"bao-huyet-tu-dai-hung-thu","name":"Bảo huyết tứ đại hung thú","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tẩy lễ","phamCap":"Chí cường hung thú","soHuu":["Liễu Thần","Thạch Hạo"],"trangThai":"da-dung","blurb":"Bốn giọt thần dịch cô đọng từ bảo huyết của Thôn Thiên Tước, sinh linh Nghi Sơn, Cùng Kỳ và sinh linh Nam Lĩnh Thần Sơn.","detail":"Bảo huyết tứ đại hung thú được Liễu Thần tế luyện, chứa trong bốn bình ngọc và dùng làm nền tảng Cực Cảnh Tẩy Lễ cho Thạch Hạo. Khi bốn bình vỡ, thần dịch nổ tung thành thần uy hủy diệt nhưng được cành liễu thuần hóa thành thác cam lộ trút xuống người hắn.","nguon":["@c0224"]},{"id":"than-tinh-tinh-hoa-cua-lieu-than","name":"Thần tính tinh hoa của Liễu Thần","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tinh hoa","phamCap":"Thần tính tinh hoa","soHuu":["Liễu Thần","Thạch Hạo"],"trangThai":"da-dung","blurb":"Chất lỏng thần tính nhỏ xuống từ hơn mười cành liễu xanh của Liễu Thần trong lần tẩy lễ.","detail":"Thần tính tinh hoa của Liễu Thần mang sinh mệnh khí cơ mênh mông như biển. Khi được buông xuống, nó khiến thảm thực vật quanh Thạch thôn tươi tốt, cây khô hồi sinh, người bệnh cũ khỏi hẳn và tộc lão cao niên trở nên hồng hào; phần tinh hoa trọng yếu được tưới vào mười Động Thiên của Thạch Hạo để trợ hắn phá cực hạn.","nguon":["@c0224"]},{"id":"bon-binh-ngoc","name":"Bốn bình ngọc","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"hong","blurb":"Bốn bình ngọc chứa bốn giọt bảo huyết tứ đại hung thú dùng trong Cực Cảnh Tẩy Lễ.","detail":"Khi Liễu Thần tuyên bố bắt đầu tẩy lễ, bốn bình ngọc lập tức vỡ tan, để bốn giọt thần dịch trong suốt bay lên và nổ tung thành luồng thần uy dữ dội.","nguon":["@c0224"]},{"id":"chat-long-cua-lieu-than","name":"Chất lỏng của Liễu thần","aliases":[],"cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"Thần tính sinh cơ","soHuu":["Liễu thần","Nhóc Tỳ"],"trangThai":"đã dùng trong tu luyện và chữa thương","blurb":"Dịch thể trong suốt rực rỡ của Liễu thần, được Nhóc Tỳ dùng làm sinh cơ khi diễn biến lại Động Thiên.","detail":"Chất lỏng này được ví như mầm mống sinh mạng, rót vào Động Thiên khiến sinh cơ bừng bừng. Trong quá trình tự hủy và tái tạo Động Thiên, Nhóc Tỳ dựa vào nguồn sinh cơ này để thử diễn biến vạn vật và hỗ trợ chữa thương.","nguon":["@c0225"]},{"id":"than-dich","name":"Thần dịch","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tu luyện","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"đã dùng một phần","blurb":"Chất lỏng óng ánh còn dư được Nhóc Tỳ dùng trong lần tẩy lễ cuối. Thần tính tinh hoa của nó sôi trào khi mười Động Thiên va chạm dữ dội.","detail":"Trong chương 226, Nhóc Tỳ dùng phần thần dịch còn lại để tiến hành lần tẩy lễ và đánh cược cuối cùng ở Động Thiên cảnh. Khi quá trình biến hóa trở nên mãnh liệt, thần tính tinh hoa trong thần dịch sôi trào như đại dương, trợ lực cho mười Động Thiên tương liên hóa thành thần hoàn.","nguon":["@c0226"]},{"id":"bia-ky-luc-dong-thien-chi-ton","name":"Bia Kỷ Lục Động Thiên Chí Tôn","cn":"","category":"khac","categoryLabel":"Bia đá chứng nhận","phamCap":"không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"hiển hiện trong Hư Thần Giới","blurb":"Bia đá hiện ra sau khi Nhóc Tỳ được xác nhận là người mạnh nhất Động Thiên cảnh trong Hư Thần Giới ở Hoang Vực. Trên bia chỉ có bốn chữ Động Thiên Chí Tôn.","detail":"Bia Kỷ Lục Động Thiên Chí Tôn là bia đá lấp lánh văn tự, do Hư Thần Giới dựng lên để chứng nhận thành tựu của Nhóc Tỳ ở Động Thiên cảnh. Nó đánh dấu địa vị chưa ai đột phá được trong thế giới tinh thần tại Hoang Vực vào thời điểm này.","nguon":["@c0228"]},{"id":"ky-luc-bia-thach-nghi","name":"Kỷ lục bia của Thạch Nghị","aliases":["Bia của Thạch Nghị","Kỷ lục bia"],"cn":"","category":"khac","categoryLabel":"Bia kỷ lục","phamCap":"thần thạch thiên thạch","soHuu":["Võ Vương Phủ","Thạch Nghị"],"trangThai":"bị phá nát @c0229","blurb":"Tấm bia kỷ lục đặt tại Diễn Võ Trường Võ Vương Phủ, làm từ thiên thạch vũ trụ và khắc chưởng ấn của Thạch Nghị. Khi Nhóc Tỳ đặt tay lên chưởng ấn, tấm bia nổ tung chia năm xẻ bảy.","detail":"Kỷ lục bia của Thạch Nghị được đặt ở vị trí bắt mắt tại Diễn Võ Trường, chất liệu là thiên thạch vũ trụ, ngưng kết sức mạnh thần bí và vốn được xem là cứng không thể phá. Trên bia có chưởng ấn do Thạch Nghị lưu lại bằng sức mạnh Chí Tôn Cốt, để người cùng thế hệ lĩnh ngộ pháp và đạo; cảm ứng từ xương ngực Nhóc Tỳ khiến nó nổ tung trong thần quang.","nguon":["@c0229"]},{"id":"canh-cay-ong-anh-lieu-than","name":"Cành cây óng ánh của Liễu Thần","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cành cây dài bằng lòng bàn tay, óng ánh, do Liễu Thần trao cho Thạch Hạo để triệu cứu viện.","detail":"Liễu Thần trao cho Thạch Hạo một cành cây dài bằng lòng bàn tay, óng ánh; khi cần thiết Liễu Thần sẽ chạy tới cứu viện thông qua vật này.","nguon":["@c0231"]},{"id":"cay-dao-bac","name":"Cây đào bạc","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Gần thánh dược","soHuu":[],"trangThai":"dang-co","blurb":"Cây đào bạc trồng ở Thạch Thôn, gần đạt tới thánh dược, tỏa linh khí lớn.","detail":"Trồng ở Thạch Thôn, sau mấy tháng biến hóa lớn cùng các linh dược khác, cây đào bạc gần đạt tới thánh dược và tỏa ra linh khí dồi dào.","nguon":["@c0231"]},{"id":"trung-than-bat-tran-ke","name":"Trứng thần của Bát Trân Kê","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":[],"trangThai":"dang-co","blurb":"Trứng thần do con Bát Trân Kê sống gần Liễu Thần đẻ ra, là bảo dược duy trì lâu dài.","detail":"Con Bát Trân Kê sinh sống gần Liễu Thần trong Thạch Thôn bắt đầu đẻ trứng thần, một loại bảo dược có tác dụng nuôi dưỡng lâu dài.","nguon":["@c0231"]},{"id":"chuan-thanh-duoc","name":"Chuẩn Thánh Dược","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Chuẩn Thánh","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Linh dược quý trong Thạch Thôn, nay đã ra hoa kết quả, bên cạnh mấy chục gốc linh dược khác.","detail":"Trong lúc tộc nhân tiễn biệt Thạch Hạo, họ cho biết Thạch Thôn nay không thiếu gì: có mấy chục gốc linh dược, Chuẩn Thánh Dược đã ra hoa kết quả, lại còn có Bát Trân Kê.","nguon":["@c0232"]},{"id":"bao-thuat-con-bang","name":"Bảo thuật Côn Bằng","cn":"","category":"khac","categoryLabel":"Bảo thuật","phamCap":"Đại thần thông Thái Cổ","soHuu":[],"trangThai":"dang-co","blurb":"Đại thần thông của thập hung Thái Cổ Côn Bằng, mục tiêu mà liên minh các thế lực muốn đoạt được ở Hải Vực.","detail":"Bảo thuật của thập hung Thái Cổ Côn Bằng, cất giấu ở hang ổ/thần sào Côn Bằng trong Hải Vực. Nhiều thế lực lớn liên hợp thành liên minh, tập hợp các thiếu niên nam nữ Hóa Linh Cảnh làm chủ lực, cùng nhau ra biển với hi vọng đoạt được bảo thuật này.","nguon":["@c0233"]},{"id":"linh-duoc-khe-nui","name":"Linh dược khe núi","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Mao Cầu"],"trangThai":"da-dung","blurb":"Cây linh dược mọc từ khe núi trên Thiên Thần Sơn mà Nhóc Tỳ ngắt cho Mao Cầu ăn.","detail":"Một cây linh dược mọc từ trong khe núi trên Thái Cổ Thần Sơn, được Nhóc Tỳ ngắt và đưa cho con vật nhỏ màu vàng Mao Cầu ăn ngon lành khi vừa lên tới thần sơn.","nguon":["@c0233"]},{"id":"thong-dao-nam-mau","name":"Thông đạo năm màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tổ phụ thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Con đường năm màu nối liền trời cao trên đỉnh Thần Sơn, đưa đại quân tới Bắc Hải.","detail":"Con đường năm màu nối liền trời cao ở đỉnh Thần Sơn, đưa đại quân sáu bảy trăm người tới Bắc Hải cách xa mấy trăm vạn dặm. Cần tôn giả (tổ phụ thiếu nữ áo tím) mới mở ra được.","nguon":["@c0234"]},{"id":"bao-thuyen-hat-cay","name":"Bảo thuyền hạt cây","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"hong","blurb":"Thuyền nhỏ điêu khắc từ một hạt cây, thả xuống biển biến lớn như núi di động.","detail":"Thuyền nhỏ điêu khắc từ một hạt cây, thả xuống biển liền biến lớn như một tòa núi di động, tốc độ như phi hành. Lão bộc dùng nó vượt biển nhưng sau ngàn dặm thì bị quái ngư bạc phóng lôi đình đánh nổ tung.","nguon":["@c0234"]},{"id":"tam-da-thu-che-cho","name":"Tấm da thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"hong","blurb":"Hai tấm da thú phủ kín trời biển, phù văn dày đặc thánh huy, dùng che chở và nâng đỡ người bay.","detail":"Hai tấm da thú lão bộc ném ra phủ kín cả trời biển, khắc phù văn dày đặc phát thánh huy; dùng để che chở đoàn người và làm nền như lục địa nâng đỡ hơn ba trăm người bay trên không. Về sau bị Thánh Giả không đầu dùng chiến mâu vàng chém thành nhiều mảnh.","nguon":["@c0234"]},{"id":"co-bao-than-son-sung-thu","name":"Cổ bảo Thần Sơn (sừng thú)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"dang-co","blurb":"Chiếc sừng thú cổ bảo của Thần Sơn, thổi ra thanh âm phá tan phù văn Hải Ma.","detail":"Chiếc sừng thú là cổ bảo của Thần Sơn; khi thổi phát ra thanh âm như tiếng gầm thét của Thần Linh, xuyên thủng phong ba và phá tan phù văn của đại trận Hải Ma, mở đường cho đoàn chạy trốn. Dùng để ứng phó những nguy cơ nghiêm trọng như thế.","nguon":["@c0234"]},{"id":"chien-mau-vang","name":"Chiến mâu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thánh Giả không đầu"],"trangThai":"dang-co","blurb":"Thanh chiến mâu vàng óng của Thánh Giả không đầu, chém rời cả bầu trời.","detail":"Thanh chiến mâu vàng óng trong tay Thánh Giả không đầu; chém rời cả bầu trời, cắt tấm da thú che chở của đoàn thành nhiều mảnh.","nguon":["@c0234"]},{"id":"long-giao-tien","name":"Long Giao Tiễn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Vật phẩm màu vàng Thạch Hạo điều động để thoát ly chiến trường nhanh chóng.","detail":"Long Giao Tiễn là pháp bảo màu vàng của Thạch Hạo. Trong cuộc thảm sát của Thánh Giả không đầu, Thạch Hạo im lặng điều động Long Giao Tiễn màu vàng để nhanh chóng thoát ly khỏi chiến trường về phía trước.","nguon":["@c0235"]},{"id":"sung-thu-chi-bao","name":"Sừng thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":[],"trangThai":"dang-co","blurb":"Sừng cổ thú chí bảo, thần bộc thổi phát gợn sóng bạc chấn động biển; dùng như thuyền lớn lướt sóng và bọc bảo quang bảo vệ.","detail":"Sừng thú là chí bảo của các thần bộc Thần Sơn Thái Cổ. Thổi lên phát ra gợn sóng bạc chấn động biển đông, có thể dùng như thuyền lớn lướt sóng và bọc bảo quang che chở người mang. Ai cầm sừng thú mới tránh được kiếp nạn từ chiến mâu vàng của Thánh Giả không đầu, song khi vào sâu vùng biển cấm thì tiêu hao thần lực rất lớn.","nguon":["@c0235"]},{"id":"chien-mau-vang-thanh-gia","name":"Chiến mâu vàng óng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thánh Giả không đầu"],"trangThai":"dang-co","blurb":"Vũ khí của Thánh Giả không đầu Thượng Cổ, quẹt qua là sinh linh nổ tung, có thể cắt cả bầu trời.","detail":"Chiến mâu vàng óng là vũ khí của Thánh Giả không đầu chết trận từ Thượng Cổ. Uy lực khủng khiếp: chỉ cần quẹt qua là sinh linh nổ tung, thần bộc mạnh cũng bị diệt, đường mâu như cắt cả bầu trời; đánh tan cả gợn sóng bạc do sừng thú tạo ra.","nguon":["@c0235"]},{"id":"u-linh-thuyen","name":"U Linh Thuyền","aliases":["thuyền giấy màu đen","thuyền giấy máu đen"],"cn":"","category":"khac","categoryLabel":"Di tích","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Những chiếc thuyền lạc đường từ thời Thượng Cổ trong vùng biển tử vong, có đuốc xanh, không âm thanh; tới gần sẽ bị giết.","detail":"U Linh Thuyền là những chiếc chiến thuyền lạc đường từ thời Thượng Cổ trôi dạt trong vùng biển tử vong. Chúng thắp đuốc xanh, không phát ra âm thanh, kẻ tới gần sẽ bị giết. Cuối chương, Thạch Hạo bị sóng hất chìm rồi đạp nước xông thẳng lên một chiếc U Linh Thuyền như vậy.","nguon":["@c0235"]},{"id":"khoi-xuong-thu-thach-van","name":"Khối xương thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Vân"],"trangThai":"da-dung","blurb":"Khối xương thú cháy hừng hực khắc phù văn, hóa thành mặt trời nhỏ, dùng làm vật công kích.","detail":"Thạch Vân ném khối xương thú này nổ tung trên U Linh Thuyền với danh nghĩa kích thích thuyền bạo động hại bạch tuộc, thực chất nhằm hại Thạch Hạo đang mắc kẹt bên trong.","nguon":["@c0236"]},{"id":"tam-xoa-kich-mau-vang","name":"Tam Xoa Kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Hậu nhân Hải Thần"],"trangThai":"dang-co","blurb":"Binh khí màu vàng của hậu nhân Hải Thần tại lối vào hang ổ thật của Côn Bằng.","detail":"Hậu nhân Hải Thần dùng Tam Xoa Kích màu vàng chấn động một cái, kim quang bùng lên như sóng lớn, khiến kẻ cãi lời cùng đám người xung quanh nổ tung thành sương máu.","nguon":["@c0239"]},{"id":"viem-trap-than-tinh","name":"Viêm Trấp thần tính","cn":"","category":"nguyen-lieu","categoryLabel":"Vật chất thần tính","phamCap":"có thể luyện Thánh Khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tia vật chất thần tính tồn tại trong cơ thể Hỏa Viêm Ngư, cực kỳ hiếm và có giá trị luyện khí.","detail":"Trong cơ thể mỗi con Hỏa Viêm Ngư có một tia Viêm Trấp thần tính nhưng hàm lượng rất thấp, phải mấy ngàn con mới luyện ra một giọt. Vật chất này có thể dùng để luyện Thánh Khí.","nguon":["@c0239"]},{"id":"hoa-phu","name":"Hỏa Phù","cn":"","category":"khac","categoryLabel":"Phù văn hỏa đạo","phamCap":"không rõ","soHuu":["Hỏa Viêm Ngư"],"trangThai":"khong-ro","blurb":"Loại phù do Hỏa Viêm Ngư trời sinh thai nghén, gắn với năng lực Hỏa Tinh của chủng tộc này.","detail":"Hỏa Viêm Ngư trong truyền thuyết tinh thông Hỏa Tinh và có thể thai nghén Hỏa Phù. Khi đàn cá số lượng lớn cùng xuất hiện, uy thế của Hỏa Phù hợp lại trở nên đáng sợ.","nguon":["@c0239"]},{"id":"con-moc","name":"Côn Mộc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Thần mộc","phamCap":"thần mộc truyền thuyết","soHuu":[],"trangThai":"xuất hiện trong cánh cửa cấm kỵ","blurb":"Côn Mộc là thần mộc truyền thuyết được xem như cây thông thiên nối liền người và thần. Tại cánh cửa cấm kỵ xuất hiện một khúc gỗ mục có long văn, thánh huy cùng một chiếc lá óng ánh không mục nát, khiến quần hùng điên cuồng tranh đoạt.","detail":"Côn Mộc được nhận ra qua khúc gỗ mục to bằng thùng nước, toàn thân có long văn, tỏa thánh huy và hào quang thần tính nồng nặc. Bên cạnh còn có chiếc lá trong suốt không mục nát ngâm trong dòng nước, được cho là trợ giúp ngộ đạo và tăng tốc tu hành; sự xuất hiện của nó khiến vô số sinh linh lao vào dòng sông cấm kỵ rồi nổ tung thành tro bụi.","nguon":["@c0240"]},{"id":"chien-kich-mau-vang","name":"Chiến kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo còn sót lại từ Thượng Cổ","soHuu":["Hậu nhân Hải Thần"],"trangThai":"Đang được hậu nhân Hải Thần sử dụng","blurb":"Binh khí màu vàng của hậu nhân Hải Thần, có thể chém sóng biển hoàng kim và đối kháng kiếm gãy của Thạch Hạo.","detail":"Chiến kích màu vàng là binh khí của thiếu niên Hải Tộc được xưng là hậu nhân Hải Thần. Nó chém qua sóng biển hoàng kim, đỡ trực diện kiếm gãy của Thạch Hạo trong lúc thần hoàn Mười Động Thiên bao phủ chiến trường, làm ánh sáng bùng nổ và chấn động quần hùng. Chương này mô tả nó là chí bảo còn sót lại từ Thượng Cổ, khí thế siêu phàm thoát tục.","nguon":["@c0241"]},{"id":"chien-mau-mau-mau","name":"Chiến mâu màu máu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thần mâu","soHuu":["Thiếu niên Hỏa Viêm Ngư hóa hình"],"trangThai":"Đang được thiếu niên Hỏa Viêm Ngư hóa hình sử dụng","blurb":"Binh khí màu máu của thiếu niên Hỏa Viêm Ngư hóa hình, được dùng để đánh thẳng vào hậu nhân Hải Thần.","detail":"Chiến mâu màu máu là binh khí trong tay thiếu niên Hỏa Viêm Ngư hóa hình. Nó có sắc đỏ như được đánh bóng từ máu tươi, theo chủ nhân lăng không lao tới tập kích hậu nhân Hải Thần. Trong giao chiến, chiến mâu này va chạm với chiến kích màu vàng, phát ra âm thanh điếc tai và làm phù văn bùng lên đầy trời.","nguon":["@c0241"]},{"id":"tan-cot-con-bang","name":"Tàn cốt Côn Bằng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Di cốt của một trong Thập Hung Thái Cổ","soHuu":[],"trangThai":"Được dùng để mở phong ấn lối vào hang ổ Côn Bằng","blurb":"Mảnh xương rạn nứt của Côn Bằng Thái Cổ, được các cường giả dùng để phá mở lối vào hang ổ Côn Bằng.","detail":"Tàn cốt Côn Bằng là một mảnh xương rạn nứt được nhận ra là di cốt của Côn Bằng, một trong Thập Hung Thái Cổ. Khi được điều khiển, nó phát ra kim quang như sóng biển và tràn ra phù văn màu đen. Đám cường giả sinh linh lục địa dùng mảnh tàn cốt này để làm phong ấn lối vào hang ổ Côn Bằng nứt ra, khiến sương mù hỗn độn tràn ra và mở màn cuộc tranh đoạt bảo thuật bên trong.","nguon":["@c0241"]},{"id":"tu-tinh-kiem","name":"Tử Tinh Kiếm","cn":"","aliases":["phi kiếm tím"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Tinh Ngư"],"trangThai":"đang sử dụng","blurb":"Tử Tinh Kiếm là phi kiếm màu tím của Tử Tinh Ngư, dài không quá nửa xích nhưng cực kỳ sắc bén. Khi được khí tím thúc động, nó hóa thành vầng mặt trời tím quét ngang cường giả trong đạo tràng Thái Cổ.","detail":"Thanh phi kiếm này được mô tả là luyện từ tử tinh, không tạp chất, mang khí Canh Kim và độ xuyên phá rất cao. Trong đạo tràng Côn Bằng, Tử Tinh Ngư dùng nó giết sạch cường giả cản đường, khiến quần hùng thèm thuồng vì phẩm chất sắc bén của nó.","nguon":["@c0242"]},{"id":"kim-tien","name":"Kim tiên","cn":"","aliases":["roi vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thanh Vân"],"trangThai":"đang sử dụng","blurb":"Kim tiên là vũ khí màu vàng của Thanh Vân khi truy sát Hùng Hài Tử. Nó có hình dạng đặc biệt, giống kiếm không mũi nhọn hơn là roi mềm thông thường.","detail":"Kim tiên có bốn góc cạnh, gồm hai mươi tám đốt, hình như đoản côn có cán, không phải nhuyễn tiên. Thanh Vân dùng nó trong lần tái đối đầu Thạch Hạo tại đạo tràng Thái Cổ.","nguon":["@c0242"]},{"id":"di-vat-con-bang","name":"Di vật Côn Bằng","cn":"","aliases":["Di cốt Côn Bằng","Máu cốt vảy lông Côn Bằng"],"category":"nguyen-lieu","categoryLabel":"Di vật","phamCap":"Di vật Thái Cổ","soHuu":["Hải Tộc","Bộ tộc Hải Ma","Sinh linh lục địa"],"trangThai":"da-dung","blurb":"Di vật Côn Bằng gồm máu, cốt, vảy và lông, là chìa khóa khiến cửa đá tổ Côn Bằng chấp thuận mở ra.","detail":"Các thế lực phải gộp những phần di vật Côn Bằng rời rạc: Bằng Cốt trong tay Hải Tộc, vảy cá nát do bộ tộc Hải Ma góp, nửa tàn vũ lông tơ và vết máu đen của sinh linh lục địa. Khi máu, cốt, vảy, lông hợp lại, cửa đá tổ Côn Bằng mới mở, cho quần hùng tiến vào đạo tràng bên trong.","nguon":["@c0243"]},{"id":"bia-da-con-bang","name":"Bia đá Côn Bằng","cn":"","category":"khac","categoryLabel":"Di vật khắc chữ cổ","phamCap":"Di vật Côn Bằng","soHuu":["Mao Cầu"],"trangThai":"dang-co","blurb":"Các tấm bia đá cổ do Mao Cầu kéo về trong hang ổ Côn Bằng. Chúng không ghi bí pháp thần thông mà ghi tiểu sử cuộc đời Côn Bằng khổ tu.","detail":"Mao Cầu đã trộm về tổng cộng tám tấm bia đá Côn Bằng có chữ viết xa xưa. Nội dung các bia đá không phải bảo thuật Côn Bằng mà là ghi chép về cuộc đời khổ tu của Côn Bằng; một tấm còn nhắc vùng biển này giống nơi sinh của Côn Bằng, thích hợp cho thiếu niên mài giũa.","nguon":["@c0244"]},{"id":"linh-duoc-hang-o-con-bang","name":"Linh dược hang ổ Côn Bằng","cn":"","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Mao Cầu","Thạch Hạo"],"trangThai":"da-dung","blurb":"Linh dược mọc um tùm trong vài vùng đất cấm của hang ổ Côn Bằng. Mao Cầu và Thạch Hạo đều ăn chúng trong thời gian lưu lại nơi đây.","detail":"Trong hang ổ Côn Bằng có vài vùng đất cấm mọc đầy linh dược. Mao Cầu hái ăn rất nhiều đến mức bụng căng tròn, miệng mũi tai đều trào linh khí; Thạch Hạo cũng ăn linh dược như nhai củ cải, cho thấy dược lực nơi đây rất mạnh, người bình thường khó chịu nổi.","nguon":["@c0244"]},{"id":"kien-gay","name":"Kiến gãy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Kiến gãy là pháp bảo dạng kiếm phát ra luồng ánh kiếm trong lúc các thần bộc vây công Thạch Hạo. Một nhát kiếm khiến một thần phó phải lui lại.","detail":"Trong cuộc vây công của tứ đại thần bộc, Kiến gãy phát uy bằng một luồng ánh kiếm bổ ra, buộc một thần phó phải lùi. Pháp bảo này phối hợp với Đả Thần Thạch và thần hoàn Động Thiên giúp Thạch Hạo phá thế đánh úp.","nguon":["@c0246"]},{"id":"tui-can-khon-thieu-nu-ao-den","name":"Túi Càn Khôn của thiếu nữ áo đen","cn":"","aliases":["Túi Càn Khôn"],"category":"phap-bao","categoryLabel":"Pháp bảo chứa đồ","phamCap":"Chưa rõ","soHuu":["Thiếu nữ áo đen"],"trangThai":"dang-co","blurb":"Chiếc Túi Càn Khôn tinh xảo của thiếu nữ áo đen, luyện từ da hung thú và buộc bằng dây vàng.","detail":"Túi nhỏ này chứa nhiều đồ ăn ngon, rượu thơm và linh dược cực phẩm. Thạch Hạo đánh giá nó có vẻ tốt hơn Túi Càn Khôn của mình, đồng thời cũng nảy ý cướp lấy, trong khi thiếu nữ áo đen cũng có tâm tư tương tự với túi của hắn.","nguon":["@c0247"]},{"id":"thit-thanh-loan","name":"Thịt Thanh Loan","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Bảo dược huyết nhục","phamCap":"Sinh linh thuần huyết","soHuu":["Thạch Hạo","Thiếu nữ áo đen"],"trangThai":"da-dung","blurb":"Thịt Thanh Loan dài mười mấy mét, được xưng là sinh linh thuần huyết và ẩn chứa nhiều thần năng.","detail":"Trong bữa tiệc trên U Linh Thuyền, Thạch Hạo và thiếu nữ áo đen ăn hơn nửa con Thanh Loan, dùng huyết nhục bảo dược này cùng Hầu Nhi Tửu để bổ sung và củng cố thân thể. Thiếu nữ áo đen ăn còn nhanh hơn Thạch Hạo, khiến hắn chịu thua ở mặt ăn uống.","nguon":["@c0247"]},{"id":"dai-kich-mau-vang","name":"Đại kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"không rõ","soHuu":["Mạc Thương"],"trangThai":"đang sử dụng","blurb":"Đại kích màu vàng là binh khí của Mạc Thương trong trận quyết chiến trên tế đàn.","detail":"Khi Mạc Thương ra tay, đại kích màu vàng tăng vọt hơn mười trượng, phù văn bao phủ và bổ xuống Thạch Hạo. Nó là vũ khí chính giúp Mạc Thương mở đầu cuộc chiến sinh tử với Thạch Hạo trên tế đàn.","nguon":["@c0252"]},{"id":"than-chieu-dang","name":"Thần Chiếu Đăng","cn":"","aliases":["Thần Chiếu Thanh Đồng Đăng","Thanh Đông Đăng"],"category":"phap-bao","categoryLabel":"Thái cổ pháp khí","phamCap":"Thái cổ pháp khí","soHuu":["Hàn Thiên"],"trangThai":"bị Hàn Thiên đoạt trong động phủ Côn Bằng","blurb":"Cổ đăng thần bí dùng thần huyết làm dầu, vốn được đặt trong động phủ Côn Bằng để chiếu sáng.","detail":"Thần Chiếu Thanh Đồng Đăng là thái cổ pháp khí cường đại tuyệt luân, được hai Tôn Giả tranh đoạt. Hàn Thiên mặc giáp đỏ thẫm lao vào và đoạt cổ đăng khỏi tay họ; trong động phủ Côn Bằng, vật này chỉ được dùng như đèn chiếu sáng, càng làm nổi bật quy mô thần tàng bên trong.","nguon":["@c0254"]},{"id":"duoc-tan-dan-phuong-hai-than","name":"Dược tán đan phương Hải Thần","cn":"","aliases":["Dược tán","viên đan xanh lam"],"category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Luyện từ thiên địa thần trân và một phần thánh dược","soHuu":["Mạc Thương"],"trangThai":"đã dùng","blurb":"Bảo dược Mạc Thương dùng để chữa vết thương xuyên ngực do Thạch Hạo gây ra.","detail":"Viên đan phát ánh xanh lam, tỏa hương khí khắp hải vực. Nó không phải Hải Thần Đan chân chính mà là dược tán luyện theo đan phương Hải Thần lưu lại, trộn thiên địa thần trân và một phần thánh dược, có thể khiến da thịt mọc lại từ xương trắng và đưa chiến lực Mạc Thương về đỉnh phong.","nguon":["@c0254"]},{"id":"linh-hai-than-dich-con-bang","name":"Linh hải / thần dịch Côn Bằng","cn":"","aliases":["Ao thần dịch","Thần dịch Côn Bằng"],"category":"dan-duoc","categoryLabel":"Thần dịch","phamCap":"Giá trị liên thành","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo thu hơn mười giọt cuối","blurb":"Ao thần dịch màu xanh lam như ngọc tủy nằm trong đạo tràng Côn Bằng.","detail":"Linh hải là tinh hoa biển cả ngưng tụ, màu xanh lam như ngọc tủy. Tuy không bằng Bất Lão tuyền, nó vẫn cực kỳ quý hiếm, có thể dùng làm thuốc và luyện khí; khi mọi người tranh đoạt, Thạch Hạo kịp thu hơn mười giọt cuối.","nguon":["@c0254"]},{"id":"te-dan-lo-cot-chien-tranh","name":"Tế đàn / lô cốt chiến tranh","cn":"","aliases":["Tế đàn","Lô cốt chiến tranh"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Mạc Thương"],"trangThai":"Mạc Thương mang theo","blurb":"Pháp khí dạng tế đàn được Mạc Thương sử dụng trong đạo tràng Côn Bằng.","detail":"Mạc Thương nhảy lên tế đàn, phát tia sáng đánh chết một mảng cường giả để mở đường. Sau đó tế đàn thu nhỏ, xoay tròn rơi xuống bên hắn và hóa thành lô cốt chiến tranh có thể sát phạt tùy thời.","nguon":["@c0254"]},{"id":"than-tuu-binh-ngoc-con-bang","name":"Thần tửu bình ngọc Côn Bằng","cn":"","aliases":["bình ngọc Côn Bằng","thần tửu"],"category":"dan-duoc","categoryLabel":"Thần dịch","phamCap":"thần dịch trân quý","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo đoạt được","blurb":"Thần tửu trong bình ngọc của Côn Bằng là thần dịch chân chính, được xem là có tác dụng trị liệu khởi tử hồi sinh. Thạch Hạo đoạt được bình này trong cuộc hỗn chiến ở động phủ Côn Bằng.","detail":"Bình ngọc và chén ngọc được phát hiện sau khi một cửa đá trong đạo tràng Côn Bằng mở ra. Thần tửu bên trong được miêu tả trân quý hơn Hầu Nhi Tửu, do thần thánh cổ dược luyện thành; sau khi Mao Cầu ôm bình bỏ chạy và làm phá phong, Thạch Hạo kịp thu bình vào Túi Càn Khôn.","nguon":["@c0255"]},{"id":"ngoc-tinh-binh","name":"Ngọc Tịnh Bình","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"chí bảo","soHuu":[],"trangThai":"đang bị tranh đoạt","blurb":"Ngọc Tịnh Bình là bảo bình cắm hoa tươi trong thạch thất sâu của động phủ Côn Bằng. Mọi người ban đầu tưởng hoa là thánh dược, nhưng sau nhận ra bảo bình mới là báu vật.","detail":"Bảo bình có khí tức sinh mệnh tràn đầy, thông thể ôn nhuận và được nhận xét giống hệt chí bảo của Tiểu Tây Thiên. Việc Côn Bằng chỉ dùng nó để cắm hoa càng cho thấy lai lịch bất phàm, khiến bốn năm vương hầu lập tức đại chiến tranh đoạt.","nguon":["@c0255"]},{"id":"bo-doan-con-bang","name":"Bồ đoàn Côn Bằng","cn":"","aliases":["bồ đoàn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo đoạt được","blurb":"Bồ đoàn Côn Bằng là vật Côn Bằng từng ngồi nghỉ trong động phủ, có bản thể bện từ rễ cây non màu xanh biếc như ngọc. Nó nặng hơn mười vạn cân và cực kỳ kiên cố.","detail":"Trong khi nhiều người tranh Ngọc Tịnh Bình, Thạch Hạo nhắm đến bồ đoàn này. Khi lộ bản thể, bồ đoàn tỏa khí tức tường hòa, nặng hơn mười vạn cân; Thạch Hạo dùng nó như búa đánh văng đại ấn của lão giả Hóa Linh cảnh, cho thấy độ cứng chắc vượt thường.","nguon":["@c0255"]},{"id":"chan-giao-dan-doc-dan","name":"Chân Giao Đan","cn":"","aliases":["độc đan","độc tán Chân Giao"],"category":"dan-duoc","categoryLabel":"Độc đan","phamCap":"đan dược thất bại","soHuu":[],"trangThai":"hóa thành sương mù độc","blurb":"Chân Giao Đan là lò đan Côn Bằng từng luyện từ Chân Giao Thái Cổ nhưng thất bại. Vì không được xử lý, nó hóa thành độc đan, độc tán và thả ra sương mù đen kịch độc.","detail":"Sương mù đen từ dược lô giết hại nhiều người, kể cả vương hầu, trước khi bị Hàn Thiên dùng Thần Chiếu Đăng luyện hóa sạch. Giao Tôn Giả thuộc Giao tộc cảm ứng được dấu vết Chân Giao trong độc tán này.","nguon":["@c0255"]},{"id":"cot-thap","name":"Cốt Tháp","cn":"","aliases":["tiểu tháp sáng long lanh"],"category":"phap-bao","categoryLabel":"Bảo khí","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"ẩn trên tóc Thạch Hạo","blurb":"Cốt Tháp là tiểu tháp sáng long lanh cao chưa đầy một tấc, ẩn trên tóc Thạch Hạo. Nó lần đầu lên tiếng trong động phủ Côn Bằng và giao dịch bằng Hỗn Độn Thổ.","detail":"Cốt Tháp phát ra ý chí yếu ớt, đòi trao đổi với Thạch Hạo: nuốt hơn phân nửa Hỗn Độn Thổ của Linh Lung Tháp để đổi lấy một lần cơ hội cứu mạng, có thể dùng để trấn giết địch hoặc phá hư không bỏ chạy khi gặp tuyệt cảnh. Nó còn được nhắc là bảo khí từng khiến Liễu Thần nghiêm túc và không muốn đề cập.","nguon":["@c0256"]},{"id":"linh-lung-thap","name":"Linh Lung Tháp","cn":"","aliases":["bảo tháp Hỗn Độn Thổ"],"category":"phap-bao","categoryLabel":"Khí phôi","phamCap":"thánh vật","soHuu":["Thạch Hạo","Cốt Tháp"],"trangThai":"bị Cốt Tháp nuốt phần lớn Hỗn Độn Thổ","blurb":"Linh Lung Tháp là bảo tháp đúc từ Hỗn Độn Thổ trong hàn đàm Luyện Binh Địa. Nó có linh tính, trân quý hơn kiếm phôi Long Cốt Thiết.","detail":"Bảo tháp này là khí phôi thời Thái Cổ, lưu lại hỗn độn phù văn và được xem là bảo cụ khó phá hủy. Thạch Hạo bắt được nó giữa vòng vây tranh đoạt, nhưng Cốt Tháp sau đó nuốt hơn phân nửa Hỗn Độn Thổ, chỉ để lại mảnh vụn cho Đả Thần Thạch.","nguon":["@c0256"]},{"id":"bo-doan-con-moc","name":"Bồ đoàn côn mộc","cn":"","aliases":["bồ đoàn màu xanh"],"category":"phap-bao","categoryLabel":"Thần trân","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"được thu vào Túi Càn Khôn","blurb":"Bồ đoàn côn mộc là bồ đoàn màu xanh bện từ côn mộc, từng được Côn Bằng ngồi qua. Nó có thể liên thông Thần giới và tiếp cận đạo bổn nguyên.","detail":"Trong động phủ Côn Bằng, vật này khiến nhiều cường giả và cả Tôn Giả tranh đoạt. Thạch Hạo dùng mười tòa Động Thiên hóa thần hoàn chém địch rồi thu bồ đoàn vào Túi Càn Khôn.","nguon":["@c0256"]},{"id":"kiem-thai-long-cot-thiet","name":"Kiếm thai Long Cốt Thiết","cn":"","category":"phap-bao","categoryLabel":"Khí phôi","phamCap":"thánh bảo","soHuu":[],"trangThai":"ở hàn đàm Luyện Binh Địa","blurb":"Kiếm thai Long Cốt Thiết là kiếm phôi thông linh trong hàn đàm Luyện Binh Địa. Nó được đúc từ Long Cốt Thiết, tài liệu cực phẩm gắn với Chân Long vẫn lạc trên quặng sắt.","detail":"Khí phôi này thuộc nhóm bảo cụ Côn Bằng từng luyện chế nhưng chưa tế luyện hoàn tất. Dù rất quý, nó vẫn được đánh giá kém trân quý hơn bảo tháp Hỗn Độn Thổ trong cùng hàn đàm.","nguon":["@c0256"]},{"id":"thien-hoang","name":"Thiên Hoang","cn":"","category":"than-khi","categoryLabel":"Thần binh","phamCap":"Chí cao Thiên Giai","soHuu":["Côn Bằng"],"trangThai":"gãy ba đoạn","blurb":"Thiên Hoang là đại kích cổ phác trong truyền thuyết, một trong mười đại binh khí thời thái cổ. Khi xuất hiện trên tế đàn Côn Bằng, nó đã bị cắt thành ba đoạn nhưng vẫn còn thần uy đáng sợ.","detail":"Thiên Hoang từng theo Côn Bằng chinh chiến cả đời, được xưng là chí cao trong Thiên Giai và một trong mười đại binh khí thời thái cổ. Có lời đồn nó được luyện từ Chân Long hoặc từ phù cốt Côn Bằng. Tại tế đàn, đại kích nằm giữa các thần binh, lưỡi kích ảm đạm, thân binh khí bao quanh khí hỗn độn; dù đã gãy ba đoạn, nó vẫn phóng ra tinh hà đánh bay người tới gần, khiến cả Tôn Giả và các thiên tài đều không thể câu thông hay thu lấy.","nguon":["@c0257"]},{"id":"chuy-thu-tinh-xao","name":"Chủy thủ tinh xảo","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Chủy thủ tinh xảo là một trong các binh khí thái cổ đặt trên tế đàn Côn Bằng. Nó thuộc nhóm pháp khí Côn Bằng từng dùng nhưng không đáp lại thần thức của người tranh đoạt.","detail":"Chủy thủ tinh xảo nằm trong số tám chín kiện binh khí ở nơi cao nhất của tế đàn, cùng với quạt vàng, thước đen và Thiên Hoang. Khi mọi người thử dùng thần thức câu thông, nó không có phản ứng, cho thấy các thần binh trên tế đàn không dễ bị thu phục.","nguon":["@c0257"]},{"id":"quat-mau-vang","name":"Quạt màu vàng","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Quạt màu vàng là một kiện thần binh thái cổ xuất hiện trên tế đàn Côn Bằng. Nó nằm trong nhóm pháp khí Côn Bằng từng sử dụng.","detail":"Quạt màu vàng được đặt gần Thiên Hoang ở nơi cao nhất của tế đàn. Dù mọi người, kể cả cường giả cấp Tôn Giả, cố dùng thần thức câu thông, kiện binh khí này vẫn không đáp lại.","nguon":["@c0257"]},{"id":"thuoc-mau-den","name":"Thước màu đen","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Thước màu đen là binh khí thái cổ nằm trên tế đàn Côn Bằng. Nó cùng các thần binh khác không để người ngoài dễ dàng thu phục.","detail":"Thước màu đen xuất hiện trong nhóm tám chín kiện binh khí trên tế đàn, được xem là pháp khí Côn Bằng từng dùng. Khi mọi người phát thần thức để câu thông, nó vẫn không có phản ứng.","nguon":["@c0257"]},{"id":"kiem-thai-phoi-tho-hon-don-tho","name":"Kiếm thai / phôi thô Hỗn Độn Thổ","cn":"","aliases":["Kiếm thai","Phôi thô"],"category":"phap-bao","categoryLabel":"Kiếm phôi linh tính","phamCap":"không rõ","soHuu":[],"trangThai":"đang ở tế đàn Côn Bằng","blurb":"Các kiếm thai và phôi thô có linh tính từng ẩn trong hàn đàm, sau đó chạy tới thần sào Côn Bằng. Chúng bị chấn động sau khi Thạch Hạo lấy đi tòa tháp Hỗn Độn Thổ.","detail":"Nhóm kiếm thai và phôi thô từng xuất hiện trong hàn đàm của Luyện Binh Địa. Sau biến cố Thạch Hạo bắt đi tòa tháp xây từ Hỗn Độn Thổ, chúng chạy tới thần sào và xen lẫn với những binh khí thần vật thái cổ trên tế đàn. Khi mọi người phát thần thức câu thông, chúng cũng không đáp lại.","nguon":["@c0257"]},{"id":"khoi-cot-mau-vang-phu-cot-con-bang","name":"Khối cốt màu vàng","cn":"","aliases":["Phù cốt Côn Bằng","Khối cốt màu vàng xen vân đen"],"category":"nguyen-lieu","categoryLabel":"Di cốt bảo vật","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên bệ đá tế đàn","blurb":"Khối cốt màu vàng xen vân đen nằm trên bệ đá như quan tài ở cuối tế đàn. Phù văn trên đó chằng chịt, lưu chuyển áo nghĩa chư thiên, khiến mọi người lập tức nhận ra đây là vật then chốt.","detail":"Khối cốt được đặt trên một bệ đá nằm ngang như quan tài phía trước tế đàn. Nó có màu vàng, bên trong xen lẫn đường vân màu đen, phù văn dày đặc lưu chuyển áo nghĩa chư thiên. Sự xuất hiện của nó khiến ánh mắt mọi người đều dồn tới và có người kêu lên rằng chính là vật họ tìm kiếm.","nguon":["@c0257"]},{"id":"nguyen-thuy-phu-cot-con-bang","name":"Nguyên thủy phù cốt Côn Bằng","cn":"","aliases":["Phù Cốt Côn Bằng","bảo cốt Côn Bằng"],"category":"phap-bao","categoryLabel":"Phù cốt thái cổ","phamCap":"Một trong mười đại bảo thuật thời thái cổ","soHuu":[],"trangThai":"đang bị tranh đoạt","blurb":"Nguyên thủy phù cốt Côn Bằng là bảo vật chứa thần thông chí cao và áo nghĩa vô thượng của Côn Bằng. Nó lộ diện tại bệ đá trong thái cổ thần tàng, dẫn phát pháp tướng Côn Bằng và khiến quần hùng bùng nổ đại hỗn chiến.","detail":"Khối phù cốt có phù văn lưu động, hào quang như ngân hà, từng hiện pháp tướng Côn Bằng che kín thiên địa, uy áp mạnh tới mức nhiều người ngã xuống và cả Tôn Giả cũng lung lay. Dù bị phát hiện có vết nứt, mọi người nhận định phù văn bên trong không thiếu thốn, vẫn có thể tham ngộ; khi bị tiếp cận, bảo cốt kháng cự đẩy người chộp ra nhưng không phản kích kịch liệt.","nguon":["@c0258"]},{"id":"phap-truong-kham-than-thach","name":"Pháp trượng khảm thần thạch","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp trượng","phamCap":"không rõ","soHuu":["Thiếu nữ thiên tài Nhân Ngư Tộc"],"trangThai":"đang sử dụng","blurb":"Pháp trượng khảm thần thạch là vũ khí của thiếu nữ thiên tài Nhân Ngư Tộc trong cuộc tranh phù cốt Côn Bằng. Nó được dùng để tung phù văn và lôi điện chống lại Mạc Thương.","detail":"Pháp trượng dài hơn thước, khảm một viên thần thạch sáng chói. Khi thiếu nữ Nhân Ngư Tộc ra tay, pháp trượng phóng phù văn như sóng cùng hàng vạn luồng lôi điện, nhưng vẫn không giúp nàng thắng được Mạc Thương.","nguon":["@c0258"]}]};
